#include <stdio.h>
#include <string.h>
int main() {
    int N;
    scanf("%d", &N);
    getchar();
    int ans = 0;
    for (int i = 0; i < N; i++) {
        char line[256];
        fgets(line, sizeof(line), stdin);
        size_t len = strlen(line);
        if (len && line[len - 1] == '\n') line[--len] = '\0';
        char *p = strrchr(line, ' ');
        if (!p) continue;
        char *price = p + 1;
        int cnt8 = 0, cnt5 = 0, cnt3 = 0; bool ok = true;
        for (char *c = price; *c; ++c) {
            if (*c == '8') cnt8++;
            else if (*c == '5') cnt5++;
            else if (*c == '3') cnt3++;
            else { ok = false; break; }
        }
        if (ok && cnt8 >= cnt5 && cnt5 >= cnt3) ans++;
    }
    printf("%d\n", ans);
    return 0;
}

